import type { ParsedVariables } from '@/types';

const VARIABLE_REGEX = /\{\{(\w+)\}\}/g;

export function parseVariables(content: string): ParsedVariables {
  const variables: string[] = [];
  const seen = new Set<string>();
  let match: RegExpExecArray | null;

  const regex = new RegExp(VARIABLE_REGEX.source, 'g');
  while ((match = regex.exec(content)) !== null) {
    const name = match[1];
    if (!seen.has(name)) {
      seen.add(name);
      variables.push(name);
    }
  }

  return { template: content, variables };
}

export function replaceVariables(
  content: string,
  values: Record<string, string>
): string {
  return content.replace(VARIABLE_REGEX, (_, name: string) => {
    return values[name] ?? `{{${name}}}`;
  });
}

export function highlightVariables(content: string): string {
  return content.replace(
    VARIABLE_REGEX,
    '<span class="variable-highlight">{{$1}}</span>'
  );
}