import { useEffect, useRef } from 'react';
import { usePromptStore } from '@/store/usePromptStore';
import { Input } from '@/components/ui/input';
import { Search, X, ArrowUpDown } from 'lucide-react';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import type { SortMode } from '@/types';

const SORT_OPTIONS: { value: SortMode; label: string }[] = [
  { value: 'updated', label: '最近更新' },
  { value: 'created', label: '最近创建' },
  { value: 'copies', label: '使用最多' },
  { value: 'title', label: '按标题' },
];

export function SearchBar() {
  const { searchQuery, setSearchQuery, sortMode, setSortMode } = usePromptStore();
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        inputRef.current?.focus();
      }
      if (e.key === 'Escape' && document.activeElement === inputRef.current) {
        inputRef.current?.blur();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  const currentSortLabel = SORT_OPTIONS.find((o) => o.value === sortMode)?.label ?? '排序';

  return (
    <div className="flex items-center gap-3">
      <div className="relative flex-1">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500" />
        <Input
          ref={inputRef}
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          placeholder="搜索提示词... (⌘K)"
          className="pl-9 pr-8 h-10 bg-white/5 border-white/10 text-zinc-200 placeholder:text-zinc-600 focus:border-amber-500/30 focus:ring-amber-500/10 rounded-xl"
        />
        {searchQuery && (
          <button
            onClick={() => setSearchQuery('')}
            className="absolute right-3 top-1/2 -translate-y-1/2 text-zinc-600 hover:text-zinc-300"
          >
            <X className="w-4 h-4" />
          </button>
        )}
      </div>
      <DropdownMenu>
        <DropdownMenuTrigger className="flex items-center gap-2 px-3 py-2 h-10 rounded-xl bg-white/5 border border-white/10 text-sm text-zinc-400 hover:text-zinc-200 hover:border-white/20 transition-all duration-200">
          <ArrowUpDown className="w-4 h-4" />
          <span className="hidden sm:inline">{currentSortLabel}</span>
        </DropdownMenuTrigger>
        <DropdownMenuContent align="end" className="w-36 bg-[#1a1a24] border-white/10">
          {SORT_OPTIONS.map((opt) => (
            <DropdownMenuItem
              key={opt.value}
              onClick={() => setSortMode(opt.value)}
              className={`text-sm cursor-pointer ${
                sortMode === opt.value
                  ? 'text-amber-400'
                  : 'text-zinc-400 hover:text-zinc-200'
              }`}
            >
              {opt.label}
            </DropdownMenuItem>
          ))}
        </DropdownMenuContent>
      </DropdownMenu>
    </div>
  );
}