import { useState } from 'react';
import { motion } from 'framer-motion';
import { usePromptStore } from '@/store/usePromptStore';
import { Badge } from '@/components/ui/badge';
import {
  Copy,
  Star,
  Pin,
  Eye,
  Pencil,
  Trash2,
  Clock,
  Check,
  History,
} from 'lucide-react';
import type { Prompt } from '@/types';

interface PromptCardProps {
  prompt: Prompt;
  onPreview: (id: string) => void;
  onEdit: (id: string) => void;
  onVersionHistory: (id: string) => void;
  index: number;
}

export function PromptCard({ prompt, onPreview, onEdit, onVersionHistory, index }: PromptCardProps) {
  const {
    copyPrompt,
    toggleFavorite,
    togglePin,
    deletePrompt,
    getCategoryById,
    getTagById,
  } = usePromptStore();

  const [copied, setCopied] = useState(false);
  const category = getCategoryById(prompt.categoryId ?? '');
  const tags = prompt.tagIds.map((id) => getTagById(id)).filter(Boolean);

  const handleCopy = async (e: React.MouseEvent) => {
    e.stopPropagation();
    await navigator.clipboard.writeText(prompt.content);
    copyPrompt(prompt.id);
    setCopied(true);
    setTimeout(() => setCopied(false), 1500);
  };

  const contentPreview = prompt.content.length > 120
    ? prompt.content.slice(0, 120).replace(/\n/g, ' ') + '...'
    : prompt.content.replace(/\n/g, ' ');

  const timeAgo = (dateStr: string) => {
    const diff = Date.now() - new Date(dateStr).getTime();
    const mins = Math.floor(diff / 60000);
    if (mins < 60) return `${mins} 分钟前`;
    const hours = Math.floor(mins / 60);
    if (hours < 24) return `${hours} 小时前`;
    const days = Math.floor(hours / 24);
    if (days < 30) return `${days} 天前`;
    return new Date(dateStr).toLocaleDateString('zh-CN');
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3, delay: index * 0.05 }}
      className="group relative p-5 rounded-2xl bg-white/[0.03] border border-white/[0.06] hover:border-white/[0.12] hover:bg-white/[0.05] transition-all duration-300 cursor-pointer"
      onClick={() => onPreview(prompt.id)}
    >
      {/* Pin indicator */}
      {prompt.isPinned && (
        <div className="absolute -top-1.5 -right-1.5 w-7 h-7 rounded-full bg-amber-500/20 border border-amber-500/30 flex items-center justify-center">
          <Pin className="w-3.5 h-3.5 text-amber-400" />
        </div>
      )}

      {/* Header */}
      <div className="flex items-start justify-between mb-3">
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            {category && (
              <div
                className="w-2 h-2 rounded-full flex-shrink-0"
                style={{ backgroundColor: category.color }}
              />
            )}
            <h3 className="font-semibold text-sm text-zinc-200 truncate">
              {prompt.title}
            </h3>
          </div>
        </div>
        <div className="flex items-center gap-0.5 opacity-0 group-hover:opacity-100 transition-opacity duration-200">
          <button
            onClick={(e) => {
              e.stopPropagation();
              toggleFavorite(prompt.id);
            }}
            className={`p-1.5 rounded-lg transition-colors ${
              prompt.isFavorite
                ? 'text-amber-400 hover:text-amber-300'
                : 'text-zinc-600 hover:text-zinc-300'
            }`}
          >
            <Star className="w-3.5 h-3.5" fill={prompt.isFavorite ? 'currentColor' : 'none'} />
          </button>
          <button
            onClick={(e) => {
              e.stopPropagation();
              onVersionHistory(prompt.id);
            }}
            className="p-1.5 rounded-lg text-zinc-600 hover:text-zinc-300 transition-colors"
            title="版本历史"
          >
            <History className="w-3.5 h-3.5" />
          </button>
          <button
            onClick={(e) => {
              e.stopPropagation();
              onEdit(prompt.id);
            }}
            className="p-1.5 rounded-lg text-zinc-600 hover:text-zinc-300 transition-colors"
          >
            <Pencil className="w-3.5 h-3.5" />
          </button>
          <button
            onClick={(e) => {
              e.stopPropagation();
              if (confirm('确定要删除这个提示词吗？')) {
                deletePrompt(prompt.id);
              }
            }}
            className="p-1.5 rounded-lg text-zinc-600 hover:text-red-400 transition-colors"
          >
            <Trash2 className="w-3.5 h-3.5" />
          </button>
        </div>
      </div>

      {/* Content preview */}
      <p className="text-xs text-zinc-500 leading-relaxed mb-3 line-clamp-2 font-mono">
        {contentPreview}
      </p>

      {/* Tags */}
      {tags.length > 0 && (
        <div className="flex flex-wrap gap-1 mb-3">
          {tags.map((tag) => (
            <Badge
              key={tag!.id}
              variant="outline"
              className="text-[10px] py-0 px-2 border-white/10 text-zinc-500"
            >
              <div
                className="w-1 h-1 rounded-full mr-1"
                style={{ backgroundColor: tag!.color }}
              />
              {tag!.name}
            </Badge>
          ))}
        </div>
      )}

      {/* Footer */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3 text-xs text-zinc-600">
          <span className="flex items-center gap-1">
            <Clock className="w-3 h-3" />
            {timeAgo(prompt.updatedAt)}
          </span>
          <span>复制 {prompt.copyCount} 次</span>
        </div>
        <button
          onClick={handleCopy}
          className={`flex items-center gap-1 px-2.5 py-1.5 rounded-lg text-xs font-medium transition-all duration-200 ${
            copied
              ? 'bg-green-500/20 text-green-400 border border-green-500/30'
              : 'bg-white/5 text-zinc-400 hover:text-zinc-200 border border-white/10 hover:border-white/20'
          }`}
        >
          {copied ? (
            <>
              <Check className="w-3 h-3" />
              已复制
            </>
          ) : (
            <>
              <Copy className="w-3 h-3" />
              复制
            </>
          )}
        </button>
      </div>
    </motion.div>
  );
}