import { useState, useEffect, useMemo } from 'react';
import { usePromptStore } from '@/store/usePromptStore';
import { parseVariables, replaceVariables } from '@/utils/variables';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Copy, Check, Eye, Variable, Star, Pencil } from 'lucide-react';
import Markdown from 'react-markdown';
import remarkGfm from 'remark-gfm';

interface PreviewModalProps {
  open: boolean;
  onClose: () => void;
  promptId: string | null;
}

export function PreviewModal({ open, onClose, promptId }: PreviewModalProps) {
  const {
    getPromptById,
    copyPrompt,
    toggleFavorite,
    getCategoryById,
    getTagById,
  } = usePromptStore();

  const prompt = promptId ? getPromptById(promptId) : undefined;
  const { variables } = useMemo(
    () => (prompt ? parseVariables(prompt.content) : { variables: [] }),
    [prompt?.content]
  );

  const [values, setValues] = useState<Record<string, string>>({});
  const [copied, setCopied] = useState(false);
  const [activeTab, setActiveTab] = useState<'fill' | 'preview'>('fill');

  const category = getCategoryById(prompt?.categoryId ?? '');
  const tags = prompt?.tagIds.map((id) => getTagById(id)).filter(Boolean) ?? [];

  const renderedContent = useMemo(
    () => (prompt ? replaceVariables(prompt.content, values) : ''),
    [prompt?.content, values]
  );

  useEffect(() => {
    if (prompt) {
      const initialValues: Record<string, string> = {};
      parseVariables(prompt.content).variables.forEach((v) => {
        initialValues[v] = '';
      });
      setValues(initialValues);
      setActiveTab('fill');
    }
  }, [prompt?.id, open]);

  const handleCopy = async () => {
    await navigator.clipboard.writeText(renderedContent);
    if (prompt) copyPrompt(prompt.id);
    setCopied(true);
    setTimeout(() => setCopied(false), 1500);
  };

  if (!prompt) return null;

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="sm:max-w-[900px] max-h-[90vh] flex flex-col bg-[#14141a] border-white/10 text-zinc-200 p-0 gap-0 rounded-2xl overflow-hidden">
        <DialogHeader className="px-6 py-5 border-b border-white/5">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <DialogTitle className="text-lg font-semibold text-zinc-200">
                {prompt.title}
              </DialogTitle>
              {category && (
                <Badge
                  variant="outline"
                  className="border-white/10 text-zinc-400"
                >
                  <div
                    className="w-1.5 h-1.5 rounded-full mr-1"
                    style={{ backgroundColor: category.color }}
                  />
                  {category.name}
                </Badge>
              )}
            </div>
            <div className="flex items-center gap-2">
              <Button
                variant="ghost"
                size="sm"
                onClick={() => toggleFavorite(prompt.id)}
                className={`gap-1.5 rounded-xl ${
                  prompt.isFavorite
                    ? 'text-amber-400'
                    : 'text-zinc-500 hover:text-zinc-300'
                }`}
              >
                <Star
                  className="w-4 h-4"
                  fill={prompt.isFavorite ? 'currentColor' : 'none'}
                />
              </Button>
              <Button
                onClick={handleCopy}
                size="sm"
                className={`gap-1.5 rounded-xl ${
                  copied
                    ? 'bg-green-500/20 text-green-400 border border-green-500/30'
                    : 'bg-amber-500 hover:bg-amber-600 text-black'
                }`}
              >
                {copied ? (
                  <>
                    <Check className="w-4 h-4" />
                    已复制
                  </>
                ) : (
                  <>
                    <Copy className="w-4 h-4" />
                    复制
                  </>
                )}
              </Button>
            </div>
          </div>
          {tags.length > 0 && (
            <div className="flex flex-wrap gap-1 mt-2">
              {tags.map((tag) => (
                <Badge
                  key={tag!.id}
                  variant="outline"
                  className="text-[10px] py-0 px-2 border-white/10 text-zinc-500"
                >
                  <div
                    className="w-1 h-1 rounded-full mr-1"
                    style={{ backgroundColor: tag!.color }}
                  />
                  {tag!.name}
                </Badge>
              ))}
            </div>
          )}
        </DialogHeader>

        <div className="flex-1 flex overflow-hidden">
          {/* Variable panel */}
          {variables.length > 0 && (
            <div className="w-72 border-r border-white/5 p-4 flex flex-col">
              <div className="flex items-center gap-2 mb-4">
                <Variable className="w-4 h-4 text-cyan-400" />
                <span className="text-sm font-medium text-zinc-300">变量填写</span>
              </div>
              <div className="space-y-3 flex-1">
                {variables.map((v) => (
                  <div key={v}>
                    <label className="text-xs text-zinc-500 mb-1 block">
                      {`{{${v}}}`}
                    </label>
                    <Input
                      value={values[v] ?? ''}
                      onChange={(e) =>
                        setValues((prev) => ({ ...prev, [v]: e.target.value }))
                      }
                      placeholder={`输入 ${v}...`}
                      className="bg-white/5 border-white/10 text-zinc-200 placeholder:text-zinc-600 rounded-xl text-sm"
                    />
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Preview area */}
          <div className="flex-1 flex flex-col">
            <div className="flex items-center gap-1 px-4 py-2 border-b border-white/5">
              <button
                onClick={() => setActiveTab('fill')}
                className={`px-3 py-1.5 text-xs rounded-lg transition-colors ${
                  activeTab === 'fill'
                    ? 'bg-white/10 text-zinc-200'
                    : 'text-zinc-500 hover:text-zinc-300'
                }`}
              >
                <Eye className="w-3.5 h-3.5 inline mr-1" />
                原始内容
              </button>
              <button
                onClick={() => setActiveTab('preview')}
                className={`px-3 py-1.5 text-xs rounded-lg transition-colors ${
                  activeTab === 'preview'
                    ? 'bg-white/10 text-zinc-200'
                    : 'text-zinc-500 hover:text-zinc-300'
                }`}
              >
                <Eye className="w-3.5 h-3.5 inline mr-1" />
                预览
              </button>
            </div>
            <ScrollArea className="flex-1 p-4">
              {activeTab === 'fill' ? (
                <pre className="text-sm font-mono text-zinc-300 whitespace-pre-wrap leading-relaxed">
                  {prompt.content}
                </pre>
              ) : (
                <div className="prose prose-invert prose-sm max-w-none">
                  <Markdown remarkPlugins={[remarkGfm]}>
                    {renderedContent}
                  </Markdown>
                </div>
              )}
            </ScrollArea>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}