import { create } from 'zustand';
import type {
  Prompt,
  Category,
  Tag,
  PromptVersion,
  AppSettings,
  SortMode,
  FilterMode,
} from '@/types';
import { loadFromStorage, saveToStorage, generateId } from '@/utils/storage';
import { searchPrompts } from '@/utils/search';

const DEFAULT_CATEGORIES: Category[] = [
  { id: 'cat_dev', name: '开发编程', color: '#06b6d4', sortOrder: 0 },
  { id: 'cat_writing', name: '写作创作', color: '#f59e0b', sortOrder: 1 },
  { id: 'cat_analysis', name: '分析研究', color: '#a78bfa', sortOrder: 2 },
  { id: 'cat_design', name: '设计创意', color: '#ec4899', sortOrder: 3 },
  { id: 'cat_other', name: '其他', color: '#6b7280', sortOrder: 4 },
];

interface PromptStore {
  // Data
  prompts: Prompt[];
  categories: Category[];
  tags: Tag[];
  versions: PromptVersion[];
  settings: AppSettings;

  // UI State
  searchQuery: string;
  selectedCategoryId: string | null;
  selectedTagId: string | null;
  filterMode: FilterMode;
  sortMode: SortMode;
  sidebarOpen: boolean;

  // Actions - Prompts
  addPrompt: (data: Omit<Prompt, 'id' | 'copyCount' | 'createdAt' | 'updatedAt'>) => Prompt;
  updatePrompt: (id: string, data: Partial<Prompt>) => void;
  deletePrompt: (id: string) => void;
  copyPrompt: (id: string) => void;
  toggleFavorite: (id: string) => void;
  togglePin: (id: string) => void;

  // Actions - Categories
  addCategory: (name: string, color: string) => Category;
  updateCategory: (id: string, data: Partial<Category>) => void;
  deleteCategory: (id: string) => void;

  // Actions - Tags
  addTag: (name: string, color: string) => Tag;
  updateTag: (id: string, data: Partial<Tag>) => void;
  deleteTag: (id: string) => void;

  // Actions - Versions
  saveVersion: (promptId: string, summary?: string) => void;
  rollbackToVersion: (versionId: string) => void;
  deleteVersion: (versionId: string) => void;

  // Actions - Import/Export
  exportData: () => string;
  importData: (json: string) => { success: boolean; error?: string };
  exportByCategory: (categoryId: string) => string;

  // Actions - UI
  setSearchQuery: (query: string) => void;
  setSelectedCategory: (id: string | null) => void;
  setSelectedTag: (id: string | null) => void;
  setFilterMode: (mode: FilterMode) => void;
  setSortMode: (mode: SortMode) => void;
  toggleSidebar: () => void;

  // Computed
  getFilteredPrompts: () => Prompt[];
  getPromptById: (id: string) => Prompt | undefined;
  getVersionsForPrompt: (promptId: string) => PromptVersion[];
  getCategoryById: (id: string) => Category | undefined;
  getTagById: (id: string) => Tag | undefined;
  getStats: () => { total: number; favorites: number; totalCopies: number };
}

const TAG_COLORS = ['#f59e0b', '#06b6d4', '#a78bfa', '#ec4899', '#10b981', '#ef4444', '#f97316', '#6366f1'];

export const usePromptStore = create<PromptStore>((set, get) => ({
  // Initial data from localStorage
  prompts: loadFromStorage<Prompt[]>('prompts', []),
  categories: loadFromStorage<Category[]>('categories', DEFAULT_CATEGORIES),
  tags: loadFromStorage<Tag[]>('tags', []),
  versions: loadFromStorage<PromptVersion[]>('versions', []),
  settings: loadFromStorage<AppSettings>('settings', { defaultCategory: null }),

  // UI State
  searchQuery: '',
  selectedCategoryId: null,
  selectedTagId: null,
  filterMode: 'all',
  sortMode: 'updated',
  sidebarOpen: true,

  // --- Prompt Actions ---
  addPrompt: (data) => {
    const now = new Date().toISOString();
    const prompt: Prompt = {
      ...data,
      id: generateId(),
      copyCount: 0,
      createdAt: now,
      updatedAt: now,
    };
    set((s) => {
      const prompts = [prompt, ...s.prompts];
      saveToStorage('prompts', prompts);
      return { prompts };
    });
    // Create initial version
    get().saveVersion(prompt.id, '初始版本');
    return prompt;
  },

  updatePrompt: (id, data) => {
    set((s) => {
      const prompts = s.prompts.map((p) =>
        p.id === id ? { ...p, ...data, updatedAt: new Date().toISOString() } : p
      );
      saveToStorage('prompts', prompts);
      return { prompts };
    });
    // Auto-save version when content or title changes
    if (data.content !== undefined || data.title !== undefined) {
      get().saveVersion(id, '编辑更新');
    }
  },

  deletePrompt: (id) => {
    set((s) => {
      const prompts = s.prompts.filter((p) => p.id !== id);
      const versions = s.versions.filter((v) => v.promptId !== id);
      saveToStorage('prompts', prompts);
      saveToStorage('versions', versions);
      return { prompts, versions };
    });
  },

  copyPrompt: (id) => {
    set((s) => {
      const prompts = s.prompts.map((p) =>
        p.id === id ? { ...p, copyCount: p.copyCount + 1 } : p
      );
      saveToStorage('prompts', prompts);
      return { prompts };
    });
  },

  toggleFavorite: (id) => {
    set((s) => {
      const prompts = s.prompts.map((p) =>
        p.id === id ? { ...p, isFavorite: !p.isFavorite } : p
      );
      saveToStorage('prompts', prompts);
      return { prompts };
    });
  },

  togglePin: (id) => {
    set((s) => {
      const prompts = s.prompts.map((p) =>
        p.id === id ? { ...p, isPinned: !p.isPinned } : p
      );
      saveToStorage('prompts', prompts);
      return { prompts };
    });
  },

  // --- Category Actions ---
  addCategory: (name, color) => {
    const category: Category = {
      id: generateId(),
      name,
      color,
      sortOrder: get().categories.length,
    };
    set((s) => {
      const categories = [...s.categories, category];
      saveToStorage('categories', categories);
      return { categories };
    });
    return category;
  },

  updateCategory: (id, data) => {
    set((s) => {
      const categories = s.categories.map((c) =>
        c.id === id ? { ...c, ...data } : c
      );
      saveToStorage('categories', categories);
      return { categories };
    });
  },

  deleteCategory: (id) => {
    set((s) => {
      const categories = s.categories.filter((c) => c.id !== id);
      const prompts = s.prompts.map((p) =>
        p.categoryId === id ? { ...p, categoryId: null } : p
      );
      saveToStorage('categories', categories);
      saveToStorage('prompts', prompts);
      return { categories, prompts };
    });
  },

  // --- Tag Actions ---
  addTag: (name, color) => {
    const tag: Tag = {
      id: generateId(),
      name,
      color: color || TAG_COLORS[Math.floor(Math.random() * TAG_COLORS.length)],
    };
    set((s) => {
      const tags = [...s.tags, tag];
      saveToStorage('tags', tags);
      return { tags };
    });
    return tag;
  },

  updateTag: (id, data) => {
    set((s) => {
      const tags = s.tags.map((t) => (t.id === id ? { ...t, ...data } : t));
      saveToStorage('tags', tags);
      return { tags };
    });
  },

  deleteTag: (id) => {
    set((s) => {
      const tags = s.tags.filter((t) => t.id !== id);
      const prompts = s.prompts.map((p) => ({
        ...p,
        tagIds: p.tagIds.filter((tid) => tid !== id),
      }));
      saveToStorage('tags', tags);
      saveToStorage('prompts', prompts);
      return { tags, prompts };
    });
  },

  // --- Version Actions ---
  saveVersion: (promptId, summary = '') => {
    const prompt = get().prompts.find((p) => p.id === promptId);
    if (!prompt) return;

    const existingVersions = get().versions.filter((v) => v.promptId === promptId);
    const versionNumber = existingVersions.length + 1;

    const version: PromptVersion = {
      id: generateId(),
      promptId,
      title: prompt.title,
      content: prompt.content,
      versionNumber,
      createdAt: new Date().toISOString(),
      changeSummary: summary,
    };

    set((s) => {
      let versions = [...s.versions, version];
      // Keep only last 50 versions per prompt
      const promptVersions = versions.filter((v) => v.promptId === promptId);
      if (promptVersions.length > 50) {
        const toRemove = promptVersions.slice(0, promptVersions.length - 50);
        versions = versions.filter((v) => !toRemove.includes(v));
      }
      saveToStorage('versions', versions);
      return { versions };
    });
  },

  rollbackToVersion: (versionId) => {
    const version = get().versions.find((v) => v.id === versionId);
    if (!version) return;

    set((s) => {
      const prompts = s.prompts.map((p) =>
        p.id === version.promptId
          ? {
              ...p,
              title: version.title,
              content: version.content,
              updatedAt: new Date().toISOString(),
            }
          : p
      );
      saveToStorage('prompts', prompts);
      return { prompts };
    });

    get().saveVersion(version.promptId, `回滚到版本 ${version.versionNumber}`);
  },

  deleteVersion: (versionId) => {
    set((s) => {
      const versions = s.versions.filter((v) => v.id !== versionId);
      saveToStorage('versions', versions);
      return { versions };
    });
  },

  // --- Import/Export ---
  exportData: () => {
    const { prompts, categories, tags, versions } = get();
    return JSON.stringify({ prompts, categories, tags, versions }, null, 2);
  },

  importData: (json) => {
    try {
      const data = JSON.parse(json);
      if (!data.prompts || !Array.isArray(data.prompts)) {
        return { success: false, error: '无效的数据格式：缺少 prompts 数组' };
      }

      set((s) => {
        const prompts = [...data.prompts, ...s.prompts];
        const categories = data.categories
          ? [...data.categories, ...s.categories]
          : s.categories;
        const tags = data.tags ? [...data.tags, ...s.tags] : s.tags;
        const versions = data.versions
          ? [...data.versions, ...s.versions]
          : s.versions;

        saveToStorage('prompts', prompts);
        saveToStorage('categories', categories);
        saveToStorage('tags', tags);
        saveToStorage('versions', versions);

        return { prompts, categories, tags, versions };
      });

      return { success: true };
    } catch {
      return { success: false, error: 'JSON 解析失败，请检查文件格式' };
    }
  },

  exportByCategory: (categoryId) => {
    const { prompts, categories, tags, versions } = get();
    const filteredPrompts = prompts.filter((p) => p.categoryId === categoryId);
    const filteredVersions = versions.filter((v) =>
      filteredPrompts.some((p) => p.id === v.promptId)
    );
    return JSON.stringify(
      { prompts: filteredPrompts, categories, tags, versions: filteredVersions },
      null,
      2
    );
  },

  // --- UI Actions ---
  setSearchQuery: (query) => set({ searchQuery: query }),
  setSelectedCategory: (id) =>
    set({
      selectedCategoryId: id,
      filterMode: id ? 'category' : 'all',
      selectedTagId: null,
    }),
  setSelectedTag: (id) =>
    set({
      selectedTagId: id,
      filterMode: id ? 'tag' : 'all',
      selectedCategoryId: null,
    }),
  setFilterMode: (mode) =>
    set({
      filterMode: mode,
      selectedCategoryId: mode === 'category' ? get().selectedCategoryId : null,
      selectedTagId: mode === 'tag' ? get().selectedTagId : null,
    }),
  setSortMode: (mode) => set({ sortMode: mode }),
  toggleSidebar: () => set((s) => ({ sidebarOpen: !s.sidebarOpen })),

  // --- Computed ---
  getFilteredPrompts: () => {
    const { prompts, searchQuery, filterMode, selectedCategoryId, selectedTagId, sortMode, categories, tags } = get();

    let filtered = [...prompts];

    // Filter by mode
    if (filterMode === 'favorites') {
      filtered = filtered.filter((p) => p.isFavorite);
    } else if (filterMode === 'category' && selectedCategoryId) {
      filtered = filtered.filter((p) => p.categoryId === selectedCategoryId);
    } else if (filterMode === 'tag' && selectedTagId) {
      filtered = filtered.filter((p) => p.tagIds.includes(selectedTagId!));
    }

    // Search
    if (searchQuery.trim()) {
      const results = searchPrompts(searchQuery, filtered, categories, tags);
      filtered = results.map((r) => r.prompt);
    }

    // Sort: pinned first, then by selected mode
    filtered.sort((a, b) => {
      if (a.isPinned !== b.isPinned) return a.isPinned ? -1 : 1;
      switch (sortMode) {
        case 'copies':
          return b.copyCount - a.copyCount;
        case 'created':
          return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
        case 'title':
          return a.title.localeCompare(b.title);
        case 'updated':
        default:
          return new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime();
      }
    });

    return filtered;
  },

  getPromptById: (id) => get().prompts.find((p) => p.id === id),

  getVersionsForPrompt: (promptId) =>
    get()
      .versions.filter((v) => v.promptId === promptId)
      .sort((a, b) => b.versionNumber - a.versionNumber),

  getCategoryById: (id) => get().categories.find((c) => c.id === id),

  getTagById: (id) => get().tags.find((t) => t.id === id),

  getStats: () => {
    const { prompts } = get();
    return {
      total: prompts.length,
      favorites: prompts.filter((p) => p.isFavorite).length,
      totalCopies: prompts.reduce((sum, p) => sum + p.copyCount, 0),
    };
  },
}));