import { useState } from 'react';
import { Sidebar } from '@/components/Sidebar';
import { SearchBar } from '@/components/SearchBar';
import { PromptGrid } from '@/components/PromptGrid';
import { CreateEditModal } from '@/components/CreateEditModal';
import { PreviewModal } from '@/components/PreviewModal';
import { VersionHistoryModal } from '@/components/VersionHistoryModal';
import { Button } from '@/components/ui/button';
import { Plus } from 'lucide-react';

export default function Home() {
  const [createOpen, setCreateOpen] = useState(false);
  const [editId, setEditId] = useState<string | null>(null);
  const [previewId, setPreviewId] = useState<string | null>(null);
  const [versionHistoryId, setVersionHistoryId] = useState<string | null>(null);

  const handleCreate = () => {
    setEditId(null);
    setCreateOpen(true);
  };

  const handleEdit = (id: string) => {
    setEditId(id);
    setCreateOpen(true);
  };

  const handlePreview = (id: string) => {
    setPreviewId(id);
  };

  const handleVersionHistory = (id: string) => {
    setVersionHistoryId(id);
  };

  return (
    <div className="flex h-screen bg-[#0f0f14] overflow-hidden">
      <Sidebar />
      <main className="flex-1 flex flex-col min-w-0">
        {/* Header */}
        <header className="flex items-center gap-4 px-6 py-4 border-b border-white/5">
          <div className="flex-1">
            <SearchBar />
          </div>
          <Button
            onClick={handleCreate}
            className="gap-2 bg-amber-500 hover:bg-amber-600 text-black font-medium rounded-xl shadow-lg shadow-amber-500/20"
          >
            <Plus className="w-4 h-4" />
            新增提示词
          </Button>
        </header>

        {/* Content */}
        <div className="flex-1 overflow-y-auto px-6 py-6">
          <PromptGrid
            onPreview={handlePreview}
            onEdit={handleEdit}
            onCreate={handleCreate}
            onVersionHistory={handleVersionHistory}
          />
        </div>
      </main>

      {/* Modals */}
      <CreateEditModal
        open={createOpen}
        onClose={() => {
          setCreateOpen(false);
          setEditId(null);
        }}
        editId={editId}
      />

      <PreviewModal
        open={!!previewId}
        onClose={() => setPreviewId(null)}
        promptId={previewId}
      />

      <VersionHistoryModal
        open={!!versionHistoryId}
        onClose={() => setVersionHistoryId(null)}
        promptId={versionHistoryId}
      />
    </div>
  );
}