import { useState } from 'react';
import { usePromptStore } from '@/store/usePromptStore';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Separator } from '@/components/ui/separator';
import { Badge } from '@/components/ui/badge';
import {
  Plus,
  Star,
  FolderOpen,
  Hash,
  PanelLeftClose,
  PanelLeft,
  ChevronDown,
  Download,
  Upload,
  Trash2,
  Check,
  X,
  Pencil,
} from 'lucide-react';
import type { Category, Tag } from '@/types';

const CATEGORY_COLORS = [
  '#06b6d4', '#f59e0b', '#a78bfa', '#ec4899', '#10b981',
  '#ef4444', '#f97316', '#6366f1', '#14b8a6', '#e11d48',
];

export function Sidebar() {
  const {
    categories,
    tags,
    filterMode,
    selectedCategoryId,
    selectedTagId,
    sidebarOpen,
    setSelectedCategory,
    setSelectedTag,
    setFilterMode,
    toggleSidebar,
    addCategory,
    deleteCategory,
    updateCategory,
    addTag,
    deleteTag,
    updateTag,
    exportData,
    importData,
    getStats,
  } = usePromptStore();

  const stats = getStats();

  const [showNewCategory, setShowNewCategory] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');
  const [editingCategory, setEditingCategory] = useState<string | null>(null);
  const [editCategoryName, setEditCategoryName] = useState('');

  const [showNewTag, setShowNewTag] = useState(false);
  const [newTagName, setNewTagName] = useState('');
  const [editingTag, setEditingTag] = useState<string | null>(null);
  const [editTagName, setEditTagName] = useState('');

  const handleAddCategory = () => {
    if (newCategoryName.trim()) {
      const color = CATEGORY_COLORS[categories.length % CATEGORY_COLORS.length];
      addCategory(newCategoryName.trim(), color);
      setNewCategoryName('');
      setShowNewCategory(false);
    }
  };

  const handleAddTag = () => {
    if (newTagName.trim()) {
      addTag(newTagName.trim(), '');
      setNewTagName('');
      setShowNewTag(false);
    }
  };

  const handleExport = () => {
    const json = exportData();
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `promptvault-export-${new Date().toISOString().slice(0, 10)}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const handleImport = () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = '.json';
    input.onchange = async (e) => {
      const file = (e.target as HTMLInputElement).files?.[0];
      if (!file) return;
      const text = await file.text();
      const result = importData(text);
      if (!result.success) {
        alert(result.error);
      }
    };
    input.click();
  };

  if (!sidebarOpen) {
    return (
      <div className="flex flex-col items-center gap-4 py-4 px-2 border-r border-white/5 bg-[#0a0a0f]">
        <Button
          variant="ghost"
          size="icon"
          onClick={toggleSidebar}
          className="text-zinc-500 hover:text-zinc-300"
        >
          <PanelLeft className="w-5 h-5" />
        </Button>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full w-64 border-r border-white/5 bg-[#0a0a0f]">
      {/* Header */}
      <div className="flex items-center justify-between px-4 py-4">
        <div className="flex items-center gap-2">
          <div className="w-7 h-7 rounded-lg bg-gradient-to-br from-amber-500 to-amber-600 flex items-center justify-center">
            <span className="text-xs font-bold text-black">P</span>
          </div>
          <span className="font-semibold text-sm text-zinc-200 tracking-wide">
            PromptVault
          </span>
        </div>
        <Button
          variant="ghost"
          size="icon"
          onClick={toggleSidebar}
          className="text-zinc-600 hover:text-zinc-300"
        >
          <PanelLeftClose className="w-4 h-4" />
        </Button>
      </div>

      <Separator className="bg-white/5" />

      <ScrollArea className="flex-1 px-3 py-3">
        {/* Filter quick links */}
        <div className="space-y-1 mb-4">
          <button
            onClick={() => setFilterMode('all')}
            className={`w-full flex items-center gap-2 px-3 py-2 rounded-lg text-sm transition-all duration-200 ${
              filterMode === 'all'
                ? 'bg-amber-500/10 text-amber-400 border border-amber-500/20'
                : 'text-zinc-400 hover:text-zinc-200 hover:bg-white/5'
            }`}
          >
            <Hash className="w-4 h-4" />
            全部提示词
            <span className="ml-auto text-xs text-zinc-600">{stats.total}</span>
          </button>
          <button
            onClick={() => setFilterMode('favorites')}
            className={`w-full flex items-center gap-2 px-3 py-2 rounded-lg text-sm transition-all duration-200 ${
              filterMode === 'favorites'
                ? 'bg-amber-500/10 text-amber-400 border border-amber-500/20'
                : 'text-zinc-400 hover:text-zinc-200 hover:bg-white/5'
            }`}
          >
            <Star className="w-4 h-4" />
            我的收藏
            <span className="ml-auto text-xs text-zinc-600">{stats.favorites}</span>
          </button>
        </div>

        <Separator className="bg-white/5 mb-4" />

        {/* Categories */}
        <div className="mb-4">
          <div className="flex items-center justify-between mb-2">
            <span className="text-xs font-semibold text-zinc-500 uppercase tracking-wider">
              分类
            </span>
            <Button
              variant="ghost"
              size="icon"
              className="h-6 w-6 text-zinc-600 hover:text-zinc-300"
              onClick={() => setShowNewCategory(true)}
            >
              <Plus className="w-3.5 h-3.5" />
            </Button>
          </div>

          {showNewCategory && (
            <div className="flex items-center gap-1 mb-2">
              <Input
                value={newCategoryName}
                onChange={(e) => setNewCategoryName(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') handleAddCategory();
                  if (e.key === 'Escape') setShowNewCategory(false);
                }}
                placeholder="分类名称"
                className="h-7 text-xs bg-white/5 border-white/10"
                autoFocus
              />
              <Button
                variant="ghost"
                size="icon"
                className="h-7 w-7 text-green-500"
                onClick={handleAddCategory}
              >
                <Check className="w-3.5 h-3.5" />
              </Button>
              <Button
                variant="ghost"
                size="icon"
                className="h-7 w-7 text-zinc-500"
                onClick={() => setShowNewCategory(false)}
              >
                <X className="w-3.5 h-3.5" />
              </Button>
            </div>
          )}

          <div className="space-y-0.5">
            {categories.map((cat: Category) => (
              <div key={cat.id} className="group flex items-center">
                {editingCategory === cat.id ? (
                  <div className="flex items-center gap-1 w-full">
                    <Input
                      value={editCategoryName}
                      onChange={(e) => setEditCategoryName(e.target.value)}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') {
                          updateCategory(cat.id, { name: editCategoryName });
                          setEditingCategory(null);
                        }
                        if (e.key === 'Escape') setEditingCategory(null);
                      }}
                      className="h-7 text-xs bg-white/5 border-white/10"
                      autoFocus
                    />
                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-7 w-7 text-green-500"
                      onClick={() => {
                        updateCategory(cat.id, { name: editCategoryName });
                        setEditingCategory(null);
                      }}
                    >
                      <Check className="w-3.5 h-3.5" />
                    </Button>
                  </div>
                ) : (
                  <button
                    onClick={() => setSelectedCategory(selectedCategoryId === cat.id ? null : cat.id)}
                    className={`flex-1 flex items-center gap-2 px-3 py-2 rounded-lg text-sm transition-all duration-200 ${
                      selectedCategoryId === cat.id
                        ? 'bg-white/5 text-zinc-200 border border-white/10'
                        : 'text-zinc-400 hover:text-zinc-200 hover:bg-white/5'
                    }`}
                  >
                    <div
                      className="w-2.5 h-2.5 rounded-full flex-shrink-0"
                      style={{ backgroundColor: cat.color }}
                    />
                    <span className="truncate">{cat.name}</span>
                  </button>
                )}
                <div className="hidden group-hover:flex items-center gap-0.5">
                  <Button
                    variant="ghost"
                    size="icon"
                    className="h-6 w-6 text-zinc-600 hover:text-zinc-300"
                    onClick={() => {
                      setEditingCategory(cat.id);
                      setEditCategoryName(cat.name);
                    }}
                  >
                    <Pencil className="w-3 h-3" />
                  </Button>
                  <Button
                    variant="ghost"
                    size="icon"
                    className="h-6 w-6 text-zinc-600 hover:text-red-400"
                    onClick={() => deleteCategory(cat.id)}
                  >
                    <Trash2 className="w-3 h-3" />
                  </Button>
                </div>
              </div>
            ))}
          </div>
        </div>

        <Separator className="bg-white/5 mb-4" />

        {/* Tags */}
        <div>
          <div className="flex items-center justify-between mb-2">
            <span className="text-xs font-semibold text-zinc-500 uppercase tracking-wider">
              标签
            </span>
            <Button
              variant="ghost"
              size="icon"
              className="h-6 w-6 text-zinc-600 hover:text-zinc-300"
              onClick={() => setShowNewTag(true)}
            >
              <Plus className="w-3.5 h-3.5" />
            </Button>
          </div>

          {showNewTag && (
            <div className="flex items-center gap-1 mb-2">
              <Input
                value={newTagName}
                onChange={(e) => setNewTagName(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') handleAddTag();
                  if (e.key === 'Escape') setShowNewTag(false);
                }}
                placeholder="标签名称"
                className="h-7 text-xs bg-white/5 border-white/10"
                autoFocus
              />
              <Button
                variant="ghost"
                size="icon"
                className="h-7 w-7 text-green-500"
                onClick={handleAddTag}
              >
                <Check className="w-3.5 h-3.5" />
              </Button>
              <Button
                variant="ghost"
                size="icon"
                className="h-7 w-7 text-zinc-500"
                onClick={() => setShowNewTag(false)}
              >
                <X className="w-3.5 h-3.5" />
              </Button>
            </div>
          )}

          <div className="flex flex-wrap gap-1.5">
            {tags.map((tag: Tag) => (
              <div key={tag.id} className="group relative">
                {editingTag === tag.id ? (
                  <div className="flex items-center gap-1">
                    <Input
                      value={editTagName}
                      onChange={(e) => setEditTagName(e.target.value)}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') {
                          updateTag(tag.id, { name: editTagName });
                          setEditingTag(null);
                        }
                        if (e.key === 'Escape') setEditingTag(null);
                      }}
                      className="h-6 w-20 text-xs bg-white/5 border-white/10"
                      autoFocus
                    />
                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-6 w-6 text-green-500"
                      onClick={() => {
                        updateTag(tag.id, { name: editTagName });
                        setEditingTag(null);
                      }}
                    >
                      <Check className="w-3 h-3" />
                    </Button>
                  </div>
                ) : (
                  <Badge
                    variant="outline"
                    className={`cursor-pointer transition-all duration-200 ${
                      selectedTagId === tag.id
                        ? 'border-amber-500/50 text-amber-400 bg-amber-500/10'
                        : 'border-white/10 text-zinc-400 hover:text-zinc-200 hover:border-white/20'
                    }`}
                    onClick={() => setSelectedTag(selectedTagId === tag.id ? null : tag.id)}
                  >
                    <div
                      className="w-1.5 h-1.5 rounded-full mr-1"
                      style={{ backgroundColor: tag.color }}
                    />
                    {tag.name}
                    <button
                      className="hidden group-hover:inline-flex ml-1 text-zinc-600 hover:text-red-400"
                      onClick={(e) => {
                        e.stopPropagation();
                        deleteTag(tag.id);
                      }}
                    >
                      <X className="w-2.5 h-2.5" />
                    </button>
                    <button
                      className="hidden group-hover:inline-flex ml-0.5 text-zinc-600 hover:text-zinc-300"
                      onClick={(e) => {
                        e.stopPropagation();
                        setEditingTag(tag.id);
                        setEditTagName(tag.name);
                      }}
                    >
                      <Pencil className="w-2.5 h-2.5" />
                    </button>
                  </Badge>
                )}
              </div>
            ))}
          </div>
        </div>
      </ScrollArea>

      {/* Bottom actions */}
      <div className="px-3 py-3 border-t border-white/5">
        <div className="flex gap-1">
          <Button
            variant="ghost"
            size="sm"
            className="flex-1 text-xs text-zinc-500 hover:text-zinc-300"
            onClick={handleExport}
          >
            <Upload className="w-3.5 h-3.5 mr-1" />
            导出
          </Button>
          <Button
            variant="ghost"
            size="sm"
            className="flex-1 text-xs text-zinc-500 hover:text-zinc-300"
            onClick={handleImport}
          >
            <Download className="w-3.5 h-3.5 mr-1" />
            导入
          </Button>
        </div>
        <div className="flex items-center justify-between mt-2 px-2">
          <span className="text-xs text-zinc-600">
            {stats.total} 个提示词
          </span>
          <span className="text-xs text-zinc-600">
            复制 {stats.totalCopies} 次
          </span>
        </div>
      </div>
    </div>
  );
}