import { useState, useEffect } from 'react';
import { usePromptStore } from '@/store/usePromptStore';
import { parseVariables } from '@/utils/variables';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Badge } from '@/components/ui/badge';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Plus, X, Variable, Save, Pin } from 'lucide-react';
import type { Prompt } from '@/types';

interface CreateEditModalProps {
  open: boolean;
  onClose: () => void;
  editId?: string | null;
}

export function CreateEditModal({ open, onClose, editId }: CreateEditModalProps) {
  const {
    addPrompt,
    updatePrompt,
    getPromptById,
    categories,
    tags,
    addTag,
    togglePin,
  } = usePromptStore();

  const existingPrompt = editId ? getPromptById(editId) : null;
  const isEdit = !!existingPrompt;

  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [categoryId, setCategoryId] = useState<string | null>(null);
  const [selectedTagIds, setSelectedTagIds] = useState<string[]>([]);
  const [newTagName, setNewTagName] = useState('');

  const variables = parseVariables(content).variables;

  useEffect(() => {
    if (existingPrompt) {
      setTitle(existingPrompt.title);
      setContent(existingPrompt.content);
      setCategoryId(existingPrompt.categoryId);
      setSelectedTagIds(existingPrompt.tagIds);
    } else {
      setTitle('');
      setContent('');
      setCategoryId(null);
      setSelectedTagIds([]);
    }
  }, [existingPrompt, open]);

  const handleSave = () => {
    if (!title.trim()) return;

    if (isEdit && editId) {
      updatePrompt(editId, {
        title: title.trim(),
        content,
        categoryId,
        tagIds: selectedTagIds,
      });
    } else {
      addPrompt({
        title: title.trim(),
        content,
        categoryId,
        tagIds: selectedTagIds,
        isFavorite: false,
        isPinned: false,
      });
    }
    onClose();
  };

  const handleAddTag = () => {
    if (newTagName.trim()) {
      const tag = addTag(newTagName.trim(), '');
      setSelectedTagIds([...selectedTagIds, tag.id]);
      setNewTagName('');
    }
  };

  const toggleTag = (tagId: string) => {
    setSelectedTagIds((prev) =>
      prev.includes(tagId) ? prev.filter((id) => id !== tagId) : [...prev, tagId]
    );
  };

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="sm:max-w-[720px] max-h-[90vh] flex flex-col bg-[#14141a] border-white/10 text-zinc-200 p-0 gap-0 rounded-2xl overflow-hidden">
        <DialogHeader className="px-6 py-5 border-b border-white/5">
          <DialogTitle className="text-lg font-semibold text-zinc-200">
            {isEdit ? '编辑提示词' : '新增提示词'}
          </DialogTitle>
        </DialogHeader>

        <div className="flex-1 overflow-y-auto px-6 py-5 space-y-5">
          {/* Title */}
          <div>
            <label className="text-xs font-medium text-zinc-500 mb-1.5 block">标题</label>
            <Input
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder="输入提示词标题..."
              className="bg-white/5 border-white/10 text-zinc-200 placeholder:text-zinc-600 rounded-xl"
            />
          </div>

          {/* Content */}
          <div>
            <label className="text-xs font-medium text-zinc-500 mb-1.5 block">
              提示词内容
              <span className="ml-2 text-zinc-600">支持 {'{{变量}}'} 占位符</span>
            </label>
            <Textarea
              value={content}
              onChange={(e) => setContent(e.target.value)}
              placeholder="输入提示词内容，使用 {{变量名}} 创建变量模板..."
              className="min-h-[200px] bg-white/5 border-white/10 text-zinc-200 placeholder:text-zinc-600 rounded-xl font-mono text-sm leading-relaxed resize-none"
            />
          </div>

          {/* Variables */}
          {variables.length > 0 && (
            <div>
              <label className="text-xs font-medium text-zinc-500 mb-2 flex items-center gap-1.5">
                <Variable className="w-3.5 h-3.5" />
                检测到的变量
              </label>
              <div className="flex flex-wrap gap-2">
                {variables.map((v) => (
                  <Badge
                    key={v}
                    variant="outline"
                    className="border-cyan-500/30 text-cyan-400 bg-cyan-500/5"
                  >
                    {`{{${v}}}`}
                  </Badge>
                ))}
              </div>
            </div>
          )}

          {/* Category & Tags */}
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-xs font-medium text-zinc-500 mb-1.5 block">分类</label>
              <Select value={categoryId ?? ''} onValueChange={(v) => setCategoryId(v || null)}>
                <SelectTrigger className="bg-white/5 border-white/10 text-zinc-200 rounded-xl">
                  <SelectValue placeholder="选择分类" />
                </SelectTrigger>
                <SelectContent className="bg-[#1a1a24] border-white/10">
                  <SelectItem value="none">无分类</SelectItem>
                  {categories.map((cat) => (
                    <SelectItem key={cat.id} value={cat.id}>
                      <div className="flex items-center gap-2">
                        <div
                          className="w-2 h-2 rounded-full"
                          style={{ backgroundColor: cat.color }}
                        />
                        {cat.name}
                      </div>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div>
              <label className="text-xs font-medium text-zinc-500 mb-1.5 block">标签</label>
              <div className="flex gap-1">
                <Input
                  value={newTagName}
                  onChange={(e) => setNewTagName(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter') {
                      e.preventDefault();
                      handleAddTag();
                    }
                  }}
                  placeholder="新建标签..."
                  className="bg-white/5 border-white/10 text-zinc-200 placeholder:text-zinc-600 rounded-xl text-sm"
                />
                <Button
                  variant="outline"
                  size="icon"
                  onClick={handleAddTag}
                  className="border-white/10 text-zinc-400 hover:text-zinc-200 rounded-xl"
                >
                  <Plus className="w-4 h-4" />
                </Button>
              </div>
              {selectedTagIds.length > 0 && (
                <div className="flex flex-wrap gap-1.5 mt-2">
                  {selectedTagIds.map((tagId) => {
                    const tag = tags.find((t) => t.id === tagId);
                    return tag ? (
                      <Badge
                        key={tagId}
                        variant="outline"
                        className="border-white/10 text-zinc-400 cursor-pointer hover:border-red-500/30 hover:text-red-400 transition-colors"
                        onClick={() => toggleTag(tagId)}
                      >
                        <div
                          className="w-1.5 h-1.5 rounded-full mr-1"
                          style={{ backgroundColor: tag.color }}
                        />
                        {tag.name}
                        <X className="w-3 h-3 ml-1" />
                      </Badge>
                    ) : null;
                  })}
                </div>
              )}
              {tags.length > 0 && (
                <div className="flex flex-wrap gap-1 mt-2">
                  {tags
                    .filter((t) => !selectedTagIds.includes(t.id))
                    .map((tag) => (
                      <Badge
                        key={tag.id}
                        variant="outline"
                        className="border-white/5 text-zinc-600 cursor-pointer hover:border-white/20 hover:text-zinc-400 transition-colors"
                        onClick={() => toggleTag(tag.id)}
                      >
                        <div
                          className="w-1.5 h-1.5 rounded-full mr-1"
                          style={{ backgroundColor: tag.color }}
                        />
                        {tag.name}
                      </Badge>
                    ))}
                </div>
              )}
            </div>
          </div>

          {/* Pin toggle for edit */}
          {isEdit && existingPrompt && (
            <div className="flex items-center gap-2 pt-2">
              <Button
                variant="outline"
                size="sm"
                onClick={() => togglePin(existingPrompt.id)}
                className={`gap-1.5 rounded-xl text-xs ${
                  existingPrompt.isPinned
                    ? 'border-amber-500/30 text-amber-400 bg-amber-500/5'
                    : 'border-white/10 text-zinc-500'
                }`}
              >
                <Pin className="w-3.5 h-3.5" />
                {existingPrompt.isPinned ? '已置顶' : '置顶'}
              </Button>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="flex items-center justify-end gap-3 px-6 py-4 border-t border-white/5">
          <Button
            variant="ghost"
            onClick={onClose}
            className="text-zinc-500 hover:text-zinc-300 rounded-xl"
          >
            取消
          </Button>
          <Button
            onClick={handleSave}
            disabled={!title.trim()}
            className="gap-2 bg-amber-500 hover:bg-amber-600 text-black font-medium rounded-xl disabled:opacity-50"
          >
            <Save className="w-4 h-4" />
            {isEdit ? '保存修改' : '创建提示词'}
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}