import { useState } from 'react';
import { usePromptStore } from '@/store/usePromptStore';
import { Button } from '@/components/ui/button';
import { ScrollArea } from '@/components/ui/scroll-area';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { History, RotateCcw, Trash2, Clock, ArrowLeft } from 'lucide-react';
import { diffLines } from 'diff';

interface VersionHistoryModalProps {
  open: boolean;
  onClose: () => void;
  promptId: string | null;
}

export function VersionHistoryModal({ open, onClose, promptId }: VersionHistoryModalProps) {
  const {
    getPromptById,
    getVersionsForPrompt,
    rollbackToVersion,
    deleteVersion,
  } = usePromptStore();

  const prompt = promptId ? getPromptById(promptId) : undefined;
  const versions = promptId ? getVersionsForPrompt(promptId) : [];

  const [selectedVersionId, setSelectedVersionId] = useState<string | null>(null);
  const [diffMode, setDiffMode] = useState(false);

  const selectedVersion = versions.find((v) => v.id === selectedVersionId);

  const handleRollback = (versionId: string) => {
    if (confirm('确定要回滚到此版本吗？当前内容将被替换。')) {
      rollbackToVersion(versionId);
      onClose();
    }
  };

  const handleDelete = (versionId: string) => {
    if (confirm('确定要删除此版本吗？')) {
      deleteVersion(versionId);
      if (selectedVersionId === versionId) {
        setSelectedVersionId(null);
      }
    }
  };

  const formatTime = (dateStr: string) => {
    const d = new Date(dateStr);
    return d.toLocaleString('zh-CN', {
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
  };

  const renderDiff = (oldText: string, newText: string) => {
    const changes = diffLines(oldText, newText);
    return (
      <pre className="text-xs font-mono leading-relaxed whitespace-pre-wrap">
        {changes.map((change, i) => (
          <div
            key={i}
            className={`px-2 py-0.5 ${
              change.added
                ? 'bg-green-500/10 text-green-400'
                : change.removed
                ? 'bg-red-500/10 text-red-400'
                : 'text-zinc-500'
            }`}
          >
            {change.added ? '+ ' : change.removed ? '- ' : '  '}
            {change.value}
          </div>
        ))}
      </pre>
    );
  };

  if (!prompt) return null;

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="sm:max-w-[900px] max-h-[90vh] flex flex-col bg-[#14141a] border-white/10 text-zinc-200 p-0 gap-0 rounded-2xl overflow-hidden">
        <DialogHeader className="px-6 py-5 border-b border-white/5">
          <DialogTitle className="flex items-center gap-2 text-lg font-semibold text-zinc-200">
            {diffMode && selectedVersion ? (
              <>
                <button
                  onClick={() => setDiffMode(false)}
                  className="text-zinc-500 hover:text-zinc-300"
                >
                  <ArrowLeft className="w-4 h-4" />
                </button>
                版本对比
              </>
            ) : (
              <>
                <History className="w-5 h-5 text-amber-400" />
                {prompt.title} - 版本历史
              </>
            )}
          </DialogTitle>
        </DialogHeader>

        <div className="flex-1 flex overflow-hidden">
          {/* Version list */}
          {!diffMode && (
            <div className="w-72 border-r border-white/5 flex flex-col">
              <ScrollArea className="flex-1">
                <div className="p-3 space-y-1">
                  {versions.length === 0 ? (
                    <p className="text-sm text-zinc-600 text-center py-8">
                      暂无版本历史
                    </p>
                  ) : (
                    versions.map((version, index) => (
                      <div
                        key={version.id}
                        onClick={() => setSelectedVersionId(version.id)}
                        className={`p-3 rounded-xl cursor-pointer transition-all duration-200 ${
                          selectedVersionId === version.id
                            ? 'bg-amber-500/10 border border-amber-500/20'
                            : 'border border-transparent hover:bg-white/5'
                        }`}
                      >
                        <div className="flex items-center justify-between mb-1">
                          <span className="text-xs font-medium text-zinc-300">
                            v{version.versionNumber}
                          </span>
                          {index === 0 && (
                            <span className="text-[10px] px-1.5 py-0.5 rounded bg-green-500/10 text-green-400">
                              当前
                            </span>
                          )}
                        </div>
                        <p className="text-xs text-zinc-500 mb-1">
                          {version.changeSummary || '无描述'}
                        </p>
                        <div className="flex items-center gap-1 text-[10px] text-zinc-600">
                          <Clock className="w-3 h-3" />
                          {formatTime(version.createdAt)}
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </ScrollArea>
              {selectedVersion && (
                <div className="p-3 border-t border-white/5 flex gap-2">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => setDiffMode(true)}
                    className="flex-1 text-xs border-white/10 text-zinc-400 hover:text-zinc-200 rounded-xl"
                  >
                    对比差异
                  </Button>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => handleRollback(selectedVersion.id)}
                    className="flex-1 text-xs border-amber-500/30 text-amber-400 hover:text-amber-300 rounded-xl"
                  >
                    <RotateCcw className="w-3.5 h-3.5 mr-1" />
                    回滚
                  </Button>
                  <Button
                    variant="ghost"
                    size="icon"
                    onClick={() => handleDelete(selectedVersion.id)}
                    className="text-zinc-600 hover:text-red-400 rounded-xl"
                  >
                    <Trash2 className="w-3.5 h-3.5" />
                  </Button>
                </div>
              )}
            </div>
          )}

          {/* Content / Diff view */}
          <div className="flex-1 flex flex-col">
            {diffMode && selectedVersion ? (
              <ScrollArea className="flex-1 p-4">
                <div className="mb-2 text-xs text-zinc-500">
                  对比 v{selectedVersion.versionNumber} (旧) → 当前版本 (新)
                </div>
                {renderDiff(selectedVersion.content, prompt.content)}
              </ScrollArea>
            ) : selectedVersion ? (
              <ScrollArea className="flex-1 p-4">
                <div className="mb-3 text-xs text-zinc-500">
                  版本 {selectedVersion.versionNumber} - {selectedVersion.changeSummary}
                </div>
                <pre className="text-sm font-mono text-zinc-300 whitespace-pre-wrap leading-relaxed">
                  {selectedVersion.content}
                </pre>
              </ScrollArea>
            ) : (
              <div className="flex-1 flex items-center justify-center">
                <p className="text-sm text-zinc-600">选择一个版本查看详情</p>
              </div>
            )}
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}