import { useMemo } from 'react';
import { usePromptStore } from '@/store/usePromptStore';
import { searchPrompts } from '@/utils/search';
import { PromptCard } from '@/components/PromptCard';
import { Plus, FileText } from 'lucide-react';
import { Button } from '@/components/ui/button';
import type { Prompt } from '@/types';

interface PromptGridProps {
  onPreview: (id: string) => void;
  onEdit: (id: string) => void;
  onCreate: () => void;
  onVersionHistory: (id: string) => void;
}

export function PromptGrid({ onPreview, onEdit, onCreate, onVersionHistory }: PromptGridProps) {
  const prompts = usePromptStore((s) => s.prompts);
  const searchQuery = usePromptStore((s) => s.searchQuery);
  const filterMode = usePromptStore((s) => s.filterMode);
  const selectedCategoryId = usePromptStore((s) => s.selectedCategoryId);
  const selectedTagId = usePromptStore((s) => s.selectedTagId);
  const sortMode = usePromptStore((s) => s.sortMode);
  const categories = usePromptStore((s) => s.categories);
  const tags = usePromptStore((s) => s.tags);

  const filtered = useMemo(() => {
    let result = [...prompts];

    if (filterMode === 'favorites') {
      result = result.filter((p) => p.isFavorite);
    } else if (filterMode === 'category' && selectedCategoryId) {
      result = result.filter((p) => p.categoryId === selectedCategoryId);
    } else if (filterMode === 'tag' && selectedTagId) {
      result = result.filter((p) => p.tagIds.includes(selectedTagId));
    }

    if (searchQuery.trim()) {
      const searchResults = searchPrompts(searchQuery, result, categories, tags);
      result = searchResults.map((r) => r.prompt);
    }

    result.sort((a: Prompt, b: Prompt) => {
      if (a.isPinned !== b.isPinned) return a.isPinned ? -1 : 1;
      switch (sortMode) {
        case 'copies':
          return b.copyCount - a.copyCount;
        case 'created':
          return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
        case 'title':
          return a.title.localeCompare(b.title);
        case 'updated':
        default:
          return new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime();
      }
    });

    return result;
  }, [prompts, searchQuery, filterMode, selectedCategoryId, selectedTagId, sortMode, categories, tags]);

  if (filtered.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-24 text-center">
        <div className="w-20 h-20 rounded-2xl bg-white/[0.03] border border-white/[0.06] flex items-center justify-center mb-6">
          <FileText className="w-8 h-8 text-zinc-700" />
        </div>
        <h3 className="text-lg font-semibold text-zinc-400 mb-2">还没有提示词</h3>
        <p className="text-sm text-zinc-600 mb-6 max-w-sm">
          创建你的第一个提示词，开始高效管理你的 AI 提示词库
        </p>
        <Button
          onClick={onCreate}
          className="gap-2 bg-amber-500 hover:bg-amber-600 text-black font-medium rounded-xl"
        >
          <Plus className="w-4 h-4" />
          创建提示词
        </Button>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
      {filtered.map((prompt, index) => (
        <PromptCard
          key={prompt.id}
          prompt={prompt}
          onPreview={onPreview}
          onEdit={onEdit}
          onVersionHistory={onVersionHistory}
          index={index}
        />
      ))}
    </div>
  );
}