import type { Prompt, Category, Tag, SearchResult } from '@/types';

export function searchPrompts(
  query: string,
  prompts: Prompt[],
  categories: Category[],
  tags: Tag[]
): SearchResult[] {
  if (!query.trim()) return prompts.map((p) => ({ prompt: p, score: 0 }));

  const q = query.toLowerCase();
  const results: SearchResult[] = [];

  const categoryMap = new Map(categories.map((c) => [c.id, c]));
  const tagMap = new Map(tags.map((t) => [t.id, t]));

  for (const prompt of prompts) {
    let score = 0;

    if (prompt.title.toLowerCase().includes(q)) {
      score += 100;
      if (prompt.title.toLowerCase().startsWith(q)) score += 50;
    }

    if (prompt.content.toLowerCase().includes(q)) {
      score += 30;
    }

    const tagNames = prompt.tagIds
      .map((id) => tagMap.get(id)?.name ?? '')
      .filter(Boolean);
    for (const name of tagNames) {
      if (name.toLowerCase().includes(q)) {
        score += 60;
      }
    }

    const category = categoryMap.get(prompt.categoryId ?? '');
    if (category?.name.toLowerCase().includes(q)) {
      score += 40;
    }

    if (score > 0) {
      results.push({ prompt, score });
    }
  }

  results.sort((a, b) => b.score - a.score);
  return results;
}